import React, { useEffect, useState } from 'react';
import { BS_YEARS, BS_MONTH_NAMES, getDaysInBSMonth } from '../nepaliDate';

/**
 * NepaliDatePicker
 * Props:
 *   label       - field label string
 *   value       - { year, month, day } BS date object or null
 *   onChange    - called with { year, month, day } when any dropdown changes
 *   required    - bool
 */
export default function NepaliDatePicker({ label, value, onChange, required = false }) {
  const year  = value?.year  || '';
  const month = value?.month || '';
  const day   = value?.day   || '';

  const daysInMonth = (year && month)
    ? getDaysInBSMonth(parseInt(year), parseInt(month))
    : 32;

  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);

  const handleChange = (field, val) => {
    const updated = { year, month, day, [field]: val ? parseInt(val) : '' };
    // Reset day if it exceeds new month's days
    if (field === 'month' || field === 'year') {
      const newDays = (updated.year && updated.month)
        ? getDaysInBSMonth(parseInt(updated.year), parseInt(updated.month))
        : 32;
      if (updated.day > newDays) updated.day = '';
    }
    onChange(updated);
  };

  return (
    <div style={styles.wrapper}>
      <label style={styles.label}>
        {label}{required && <span style={styles.req}> *</span>}
      </label>
      <div style={styles.row}>
        {/* Year */}
        <select
          value={year}
          onChange={e => handleChange('year', e.target.value)}
          style={styles.select}
          required={required}
        >
          <option value="">Year</option>
          {BS_YEARS.map(y => (
            <option key={y} value={y}>{y} BS</option>
          ))}
        </select>

        {/* Month */}
        <select
          value={month}
          onChange={e => handleChange('month', e.target.value)}
          style={styles.select}
          disabled={!year}
          required={required}
        >
          <option value="">Month</option>
          {BS_MONTH_NAMES.map((name, i) => (
            <option key={i + 1} value={i + 1}>{name}</option>
          ))}
        </select>

        {/* Day */}
        <select
          value={day}
          onChange={e => handleChange('day', e.target.value)}
          style={{ ...styles.select, maxWidth: 80 }}
          disabled={!month || !year}
          required={required}
        >
          <option value="">Day</option>
          {days.map(d => (
            <option key={d} value={d}>{d}</option>
          ))}
        </select>
      </div>

      {/* Show selected date in readable form */}
      {year && month && day && (
        <div style={styles.preview}>
          📅 {day} {BS_MONTH_NAMES[month - 1]} {year} BS
        </div>
      )}
    </div>
  );
}

const styles = {
  wrapper: { display: 'flex', flexDirection: 'column', flex: 1, minWidth: 260, marginBottom: 10 },
  label:   { fontSize: 12, color: '#555', marginBottom: 4, fontWeight: 500 },
  req:     { color: '#cc0000' },
  row:     { display: 'flex', gap: 6 },
  select:  {
    flex: 1,
    padding: '8px 6px',
    border: '1px solid #c0ccd8',
    borderRadius: 5,
    fontSize: 13,
    background: '#fff',
    cursor: 'pointer',
    outline: 'none',
  },
  preview: {
    marginTop: 5,
    fontSize: 12,
    color: '#2a6098',
    fontWeight: 600,
  },
};
